class Solution {
public:
    int countCharacters(vector<string>& words, string chars) {
        int charsCount[26] = {0};
        for (char c : chars) {
            charsCount[c - 'a']++;
        }
        int res = 0;
        for (string word : words) {
            int wordCount[26] = {0};
            bool isValid = true;
            for (char c : word) {
                if (wordCount[c - 'a']++ > charsCount[c - 'a']) {
                    isValid = false;
                    break;
                }
            }
            if (isValid) {
                res += word.size();
            }
        }
        return res;
    }
};
```

